// Solution
function validateDockerComposePortMappings(config) {
  // Iterate over services
  for (var service in config) {
    // Get port mappings for the current service
    var portMappings = config[service];

    // Check if port mappings are valid
    var isValid = true;
    // If exposed port is not unique across all services, it's not valid
    for (var otherService in config) {
      if (otherService !== service && portMappings.exposed === config[otherService].exposed) {
        isValid = false;
        break;
      }
    }

    return isValid;
  }
}

