class Solution:
  def validate_docker_compose_port_mappings(self, config) -> bool:
    # Iterate over services
    for service in config:
      # Get port mappings for the current service
      port_mappings = config[service]

      # Check if port mappings are valid
      is_valid = True
      # If exposed port is not unique across all services, it's not valid
      for other_service in config:
        if other_service != service and port_mappings['exposed'] == config[other_service]['exposed']:
          is_valid = False
          break

      return is_valid
